// MARK: - CryptoHandler

enum CryptoError: Error {
    case encryptionFailed
    case decryptionFailed
    case invalidKeyOrData
    case keyGenerationFailed
}

class CryptoHandler {
    private let key: SymmetricKey

    // In a production app, the key must be securely generated and stored in Keychain, not hardcoded.
    // For this example, we'll derive a key from a string for consistent demo runs.
    init() {
        // IMPORTANT: In production, generate a strong random key (e.g., SymmetricKey(size: .bits256))
        // and securely store it in the iOS Keychain, accessible only to your app.
        // Do NOT hardcode or derive from a hardcoded password like this for production.
        let password = "ThisIsAReallySecureKeyPasswordForDemoOnlyPleaseChangeInProduction!"
        let salt = "BankingAppSaltForCryptoKey".data(using: .utf8)!
        self.key = HKDF<SHA256>.deriveKey(
            inputKeyMaterial: SymmetricKey(data: password.data(using: .utf8)!),
            salt: salt,
            outputByteCount: 32 // 256 bits for AES-256
        )
    }

    func encrypt<T: Encodable>(_ object: T) throws -> Data {
        let encoder = JSONEncoder()
        let data = try encoder.encode(object)

        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let ciphertext = sealedBox.ciphertext, let tag = sealedBox.tag, let nonce = sealedBox.nonce else {
            throw CryptoError.encryptionFailed
        }

        // Combine nonce, tag, and ciphertext into a single Data object for storage
        var combinedData = Data()
        combinedData.append(nonce.withUnsafeBytes { Data($0) }) // 12 bytes
        combinedData.append(tag) // 16 bytes
        combinedData.append(ciphertext)

        return combinedData
    }

    func decrypt<T: Decodable>(_ encryptedData: Data, type: T.Type) throws -> T {
        guard encryptedData.count >= (AES.GCM.nonceByteCount + AES.GCM.tagByteCount) else {
            throw CryptoError.decryptionFailed
        }

        let nonceData = encryptedData.prefix(AES.GCM.nonceByteCount)
        let tagData = encryptedData.subdata(in: AES.GCM.nonceByteCount..<(AES.GCM.nonceByteCount + AES.GCM.tagByteCount))
        let ciphertext = encryptedData.suffix(from: AES.GCM.nonceByteCount + AES.GCM.tagByteCount)

        guard let nonce = try? AES.GCM.Nonce(data: nonceData) else {
            throw CryptoError.decryptionFailed
        }

        let sealedBox = try AES.GCM.SealedBox(
            nonce: nonce,
            ciphertext: ciphertext,
            tag: tagData
        )

        let decryptedData = try AES.GCM.open(sealedBox, using: key)
        let decoder = JSONDecoder()
        return try decoder.decode(type, from: decryptedData)
    }
}

// MARK: - Models

struct Account: Codable, Identifiable, Hashable {
    let id: UUID
    var name: String
    var balance: Decimal
    var currency: String // e.g., "USD", "EUR"

    init(id: UUID = UUID(), name: String, balance: Decimal, currency: String = "USD") {
        self.id = id
        self.name = name
        self.balance = balance
        self.currency = currency
    }
}

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
}

struct Transaction: Codable, Identifiable, Hashable {
    let id: UUID
    let accountId: UUID // Account performing/initiating the transaction
    let type: TransactionType
    let amount: Decimal // Positive for deposit/transfer-in, negative for withdrawal/transfer-out
    let date: Date
    let description: String
    var relatedAccountId: UUID? // For transfers, the other account involved

    init(id: UUID = UUID(), accountId: UUID, type: TransactionType, amount: Decimal, date: Date = Date(), description: String, relatedAccountId: UUID? = nil) {
        self.id = id
        self.accountId = accountId
        self.type = type
        self.amount = amount
        self.date = date
        self.description = description
        self.relatedAccountId = relatedAccountId
    }
}

struct EncryptedBankingData: Codable {
    var accounts: [Account]
    var transactions: [Transaction]
}

// MARK: - BankingService

enum BankingError: Error, LocalizedError {
    case accountNotFound
    case insufficientFunds
    case invalidAmount
    case transactionFailed(String)
    case dataPersistenceError(String)

    var errorDescription: String? {
        switch self {
        case .accountNotFound: return "Account not found."
        case .insufficientFunds: return "Insufficient funds."
        case .invalidAmount: return "Invalid amount. Amount must be positive."
        case .transactionFailed(let message): return "Transaction failed: \(message)"
        case .dataPersistenceError(let message): return "Data persistence error: \(message)"
        }
    }
}

class BankingService {
    private var accounts: [UUID: Account] = [:]
    private var transactions: [Transaction] = []
    private let cryptoHandler: CryptoHandler
    private let storageKey = "encryptedBankingData"

    // Use NotificationCenter to inform UI about updates
    static let accountsUpdatedNotification = Notification.Name("BankingServiceAccountsUpdated")
    static let transactionsUpdatedNotification = Notification.Name("BankingServiceTransactionsUpdated")

    init(cryptoHandler: CryptoHandler) {
        self.cryptoHandler = cryptoHandler
        loadData()
    }

    // MARK: - Account Management

    func createAccount(name: String, initialBalance: Decimal, currency: String = "USD") -> Account {
        let newAccount = Account(name: name, balance: initialBalance, currency: currency)
        accounts[newAccount.id] = newAccount
        saveData()
        NotificationCenter.default.post(name: BankingService.accountsUpdatedNotification, object: nil)
        return newAccount
    }

    func getAccount(id: UUID) -> Account? {
        return accounts[id]
    }

    func getAllAccounts() -> [Account] {
        return Array(accounts.values)
    }

    func getTransactions(for accountId: UUID) -> [Transaction] {
        return transactions.filter { $0.accountId == accountId || $0.relatedAccountId == accountId }.sorted { $0.date > $1.date }
    }

    // MARK: - Transaction Handling

    func deposit(to accountId: UUID, amount: Decimal, description: String) throws {
        guard var account = accounts[accountId] else {
            throw BankingError.accountNotFound
        }
        guard amount > 0 else {
            throw BankingError.invalidAmount
        }

        account.balance += amount
        accounts[accountId] = account

        let newTransaction = Transaction(accountId: accountId, type: .deposit, amount: amount, description: description)
        transactions.append(newTransaction)

        saveData()
        NotificationCenter.default.post(name: BankingService.accountsUpdatedNotification, object: nil)
        NotificationCenter.default.post(name: BankingService.transactionsUpdatedNotification, object: nil)
    }

    func withdraw(from accountId: UUID, amount: Decimal, description: String) throws {
        guard var account = accounts[accountId] else {
            throw BankingError.accountNotFound
        }
        guard amount > 0 else {
            throw BankingError.invalidAmount
        }
        guard account.balance >= amount else {
            throw BankingError.insufficientFunds
        }

        account.balance -= amount
        accounts[accountId] = account

        let newTransaction = Transaction(accountId: accountId, type: .withdrawal, amount: -amount, description: description) // Negative for withdrawal
        transactions.append(newTransaction)

        saveData()
        NotificationCenter.default.post(name: BankingService.accountsUpdatedNotification, object: nil)
        NotificationCenter.default.post(name: BankingService.transactionsUpdatedNotification, object: nil)
    }

    func transfer(from fromAccountId: UUID, to toAccountId: UUID, amount: Decimal, description: String) throws {
        guard var fromAccount = accounts[fromAccountId] else {
            throw BankingError.accountNotFound
        }
        guard var toAccount = accounts[toAccountId] else {
            throw BankingError.accountNotFound
        }
        guard amount > 0 else {
            throw BankingError.invalidAmount
        }
        guard fromAccount.balance >= amount else {
            throw BankingError.insufficientFunds
        }
        guard fromAccountId != toAccountId else {
            throw BankingError.transactionFailed("Cannot transfer to the same account.")
        }

        fromAccount.balance -= amount
        toAccount.balance += amount
        accounts[fromAccountId] = fromAccount
        accounts[toAccountId] = toAccount

        let fromTransaction = Transaction(
            accountId: fromAccountId,
            type: .transfer,
            amount: -amount, // Represents money leaving this account
            description: "Transfer to \(toAccount.name): \(description)",
            relatedAccountId: toAccountId
        )
        let toTransaction = Transaction(
            accountId: toAccountId,
            type: .transfer,
            amount: amount, // Represents money entering this account
            description: "Transfer from \(fromAccount.name): \(description)",
            relatedAccountId: fromAccountId
        )

        transactions.append(fromTransaction)
        transactions.append(toTransaction)

        saveData()
        NotificationCenter.default.post(name: BankingService.accountsUpdatedNotification, object: nil)
        NotificationCenter.default.post(name: BankingService.transactionsUpdatedNotification, object: nil)
    }

    // MARK: - Data Persistence (Encrypted)

    private func saveData() {
        let bankingData = EncryptedBankingData(accounts: Array(accounts.values), transactions: transactions)
        do {
            let encryptedData = try cryptoHandler.encrypt(bankingData)
            UserDefaults.standard.set(encryptedData, forKey: storageKey)
        } catch {
            print("Error encrypting and saving data: \(error.localizedDescription)")
            // In a real app, robust error logging and user feedback would be crucial.
            // Also, consider clearing data or preventing app usage if encryption fails.
        }
    }

    private func loadData() {
        guard let encryptedData = UserDefaults.standard.data(forKey: storageKey) else {
            print("No encrypted data found. Initializing with empty data or defaults.")
            // Initialize with some dummy data for demo if empty
            if accounts.isEmpty {
                _ = createAccount(name: "Checking", initialBalance: 1000.00, currency: "USD")
                _ = createAccount(name: "Savings", initialBalance: 5000.00, currency: "USD")
            }
            return
        }

        do {
            let decryptedData = try cryptoHandler.decrypt(encryptedData, type: EncryptedBankingData.self)
            accounts = decryptedData.accounts.reduce(into: [:]) { result, account in
                result[account.id] = account
            }
            transactions = decryptedData.transactions
        } catch {
            print("Error decrypting and loading data: \(error.localizedDescription)")
            // CRITICAL: Decryption failure could mean data tampering or incorrect key.
            // In a real app, this should trigger a re-authentication, data wipe,
            // or force user to re-setup their account, reporting the issue to backend.
            // For this demo, we'll just log and continue with potentially empty data.
            accounts = [:]
            transactions = []
            // Optionally, re-create initial accounts if recovery is not possible.
            _ = createAccount(name: "Checking", initialBalance: 1000.00, currency: "USD")
            _ = createAccount(name: "Savings", initialBalance: 5000.00, currency: "USD")
        }
    }
}

// MARK: - ViewController

class AccountListViewController: UIViewController {

    private let bankingService: BankingService
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    private var selectedAccount: Account?

    private lazy var accountsTableView: UITableView = {
        let tableView = UITableView()
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "AccountCell")
        tableView.layer.cornerRadius = 8
        tableView.layer.masksToBounds = true
        tableView.backgroundColor = .secondarySystemBackground
        return tableView
    }()

    private lazy var transactionsTableView: UITableView = {
        let tableView = UITableView()
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "TransactionCell")
        tableView.layer.cornerRadius = 8
        tableView.layer.masksToBounds = true
        tableView.backgroundColor = .secondarySystemBackground
        return tableView
    }()

    private lazy var balanceLabel: UILabel = {
        let label = UILabel()
        label.translatesAutoresizingMaskIntoConstraints = false
        label.font = UIFont.systemFont(ofSize: 24, weight: .bold)
        label.textAlignment = .center
        label.numberOfLines = 0
        label.backgroundColor = .systemTeal.withAlphaComponent(0.1)
        label.layer.cornerRadius = 8
        label.layer.masksToBounds = true
        label.text = "Select an account"
        return label
    }()

    private lazy var depositButton: UIButton = {
        let button = UIButton(type: .system)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.setTitle("Deposit", for: .normal)
        button.addTarget(self, action: #selector(depositTapped), for: .touchUpInside)
        button.backgroundColor = .systemGreen.withAlphaComponent(0.2)
        button.layer.cornerRadius = 8
        return button
    }()

    private lazy var withdrawButton: UIButton = {
        let button = UIButton(type: .system)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.setTitle("Withdraw", for: .normal)
        button.addTarget(self, action: #selector(withdrawTapped), for: .touchUpInside)
        button.backgroundColor = .systemRed.withAlphaComponent(0.2)
        button.layer.cornerRadius = 8
        return button
    }()

    private lazy var transferButton: UIButton = {
        let button = UIButton(type: .system)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.setTitle("Transfer", for: .normal)
        button.addTarget(self, action: #selector(transferTapped), for: .touchUpInside)
        button.backgroundColor = .systemBlue.withAlphaComponent(0.2)
        button.layer.cornerRadius = 8
        return button
    }()

    init(bankingService: BankingService) {
        self.bankingService = bankingService
        super.init(nibName: nil, bundle: nil)
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "My Banking App"
        setupUI()
        loadAccountData()
        addObservers()
    }

    deinit {
        NotificationCenter.default.removeObserver(self)
    }

    private func setupUI() {
        let stackView = UIStackView(arrangedSubviews: [depositButton, withdrawButton, transferButton])
        stackView.translatesAutoresizingMaskIntoConstraints = false
        stackView.axis = .horizontal
        stackView.distribution = .fillEqually
        stackView.spacing = 10

        let topStack = UIStackView(arrangedSubviews: [balanceLabel, stackView])
        topStack.translatesAutoresizingMaskIntoConstraints = false
        topStack.axis = .vertical
        topStack.spacing = 20

        let mainStack = UIStackView(arrangedSubviews: [topStack, accountsTableView, transactionsTableView])
        mainStack.translatesAutoresizingMaskIntoConstraints = false
        mainStack.axis = .vertical
        mainStack.distribution = .fillProportionally
        mainStack.spacing = 15

        view.addSubview(mainStack)

        NSLayoutConstraint.activate([
            mainStack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            mainStack.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 20),
            mainStack.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -20),
            mainStack.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),

            balanceLabel.heightAnchor.constraint(equalToConstant: 80),
            stackView.heightAnchor.constraint(equalToConstant: 44),

            accountsTableView.heightAnchor.constraint(greaterThanOrEqualToConstant: 100), // Ensure minimum height
            transactionsTableView.heightAnchor.constraint(greaterThanOrEqualToConstant: 150) // Ensure minimum height
        ])
    }

    private func addObservers() {
        NotificationCenter.default.addObserver(self, selector: #selector(handleAccountsUpdated), name: BankingService.accountsUpdatedNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(handleTransactionsUpdated), name: BankingService.transactionsUpdatedNotification, object: nil)
    }

    @objc private func handleAccountsUpdated() {
        loadAccountData()
    }

    @objc private func handleTransactionsUpdated() {
        if let selectedAccount = selectedAccount {
            transactions = bankingService.getTransactions(for: selectedAccount.id)
            transactionsTableView.reloadData()
        }
    }

    private func loadAccountData() {
        accounts = bankingService.getAllAccounts()
        accountsTableView.reloadData()

        // If no account is selected, select the first one if available
        if selectedAccount == nil, let firstAccount = accounts.first {
            selectedAccount = firstAccount
            updateUIForSelectedAccount()
        } else if let currentSelectedId = selectedAccount?.id,
                  let updatedSelectedAccount = bankingService.getAccount(id: currentSelectedId) {
            // Update selected account if it was already set
            selectedAccount = updatedSelectedAccount
            updateUIForSelectedAccount()
        } else {
            // If selected account was deleted or not found, clear selection
            selectedAccount = nil
            updateUIForSelectedAccount()
        }
    }

    private func updateUIForSelectedAccount() {
        if let account = selectedAccount {
            balanceLabel.text = "Balance for \(account.name):\n\(account.currency) \(account.balance.description)"
            transactions = bankingService.getTransactions(for: account.id)
        } else {
            balanceLabel.text = "Select an account"
            transactions = []
        }
        transactionsTableView.reloadData()
        accountsTableView.reloadData() // To highlight selected row
    }

    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }

    // MARK: - Transaction Actions

    @objc private func depositTapped() {
        guard let account = selectedAccount else {
            showAlert(title: "Error", message: "Please select an account first.")
            return
        }

        let alert = UIAlertController(title: "Deposit to \(account.name)", message: "Enter amount and description", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        alert.addTextField { textField in
            textField.placeholder = "Description (Optional)"
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        alert.addAction(UIAlertAction(title: "Deposit", style: .default) { [weak self] _ in
            guard let self = self,
                  let amountString = alert.textFields?[0].text,
                  let amount = Decimal(string: amountString),
                  let description = alert.textFields?[1].text else { return }

            do {
                try self.bankingService.deposit(to: account.id, amount: amount, description: description.isEmpty ? "Deposit" : description)
                self.showAlert(title: "Success", message: "Deposit successful!")
            } catch {
                self.showAlert(title: "Error", message: error.localizedDescription)
            }
        })
        present(alert, animated: true, completion: nil)
    }

    @objc private func withdrawTapped() {
        guard let account = selectedAccount else {
            showAlert(title: "Error", message: "Please select an account first.")
            return
        }

        let alert = UIAlertController(title: "Withdraw from \(account.name)", message: "Enter amount and description", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        alert.addTextField { textField in
            textField.placeholder = "Description (Optional)"
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        alert.addAction(UIAlertAction(title: "Withdraw", style: .default) { [weak self] _ in
            guard let self = self,
                  let amountString = alert.textFields?[0].text,
                  let amount = Decimal(string: amountString),
                  let description = alert.textFields?[1].text else { return }

            do {
                try self.bankingService.withdraw(from: account.id, amount: amount, description: description.isEmpty ? "Withdrawal" : description)
                self.showAlert(title: "Success", message: "Withdrawal successful!")
            } catch {
                self.showAlert(title: "Error", message: error.localizedDescription)
            }
        })
        present(alert, animated: true, completion: nil)
    }

    @objc private func transferTapped() {
        guard let fromAccount = selectedAccount else {
            showAlert(title: "Error", message: "Please select a source account first.")
            return
        }

        let otherAccounts = accounts.filter { $0.id != fromAccount.id }
        guard !otherAccounts.isEmpty else {
            showAlert(title: "Error", message: "No other accounts available for transfer.")
            return
        }

        let alert = UIAlertController(title: "Transfer from \(fromAccount.name)", message: "Select a destination account", preferredStyle: .actionSheet)

        for otherAccount in otherAccounts {
            alert.addAction(UIAlertAction(title: "To: \(otherAccount.name)", style: .default, handler: { [weak self] _ in
                self?.promptForTransferDetails(fromAccount: fromAccount, toAccount: otherAccount)
            }))
        }

        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        // For iPad, action sheets need a popover presentation controller source view
        if let popoverController = alert.popoverPresentationController {
            popoverController.sourceView = transferButton
            popoverController.sourceRect = transferButton.bounds
        }
        present(alert, animated: true, completion: nil)
    }

    private func promptForTransferDetails(fromAccount: Account, toAccount: Account) {
        let alert = UIAlertController(title: "Transfer from \(fromAccount.name) to \(toAccount.name)", message: "Enter amount and description", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        alert.addTextField { textField in
            textField.placeholder = "Description (Optional)"
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        alert.addAction(UIAlertAction(title: "Transfer", style: .default) { [weak self] _ in
            guard let self = self,
                  let amountString = alert.textFields?[0].text,
                  let amount = Decimal(string: amountString),
                  let description = alert.textFields?[1].text else { return }

            do {
                try self.bankingService.transfer(from: fromAccount.id, to: toAccount.id, amount: amount, description: description.isEmpty ? "Transfer" : description)
                self.showAlert(title: "Success", message: "Transfer successful!")
            } catch {
                self.showAlert(title: "Error", message: error.localizedDescription)
            }
        })
        present(alert, animated: true, completion: nil)
    }
}

// MARK: - UITableViewDataSource, UITableViewDelegate

extension AccountListViewController: UITableViewDataSource, UITableViewDelegate {
    func numberOfSections(in tableView: UITableView) -> Int {
        return 1
    }

    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        if tableView == accountsTableView {
            return accounts.count
        } else {
            return transactions.count
        }
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        if tableView == accountsTableView {
            let cell = tableView.dequeueReusableCell(withIdentifier: "AccountCell", for: indexPath)
            let account = accounts[indexPath.row]
            cell.textLabel?.text = "\(account.name) - \(account.currency) \(account.balance.description)"
            cell.accessoryType = (selectedAccount?.id == account.id) ? .checkmark : .none
            cell.backgroundColor = (selectedAccount?.id == account.id) ? .systemGray5 : .clear
            return cell
        } else {
            let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
            let transaction = transactions[indexPath.row]
            let dateFormatter = DateFormatter()
            dateFormatter.dateStyle = .short
            dateFormatter.timeStyle = .short

            var textColor: UIColor = .label
            if transaction.amount < 0 {
                textColor = .systemRed
            } else if transaction.amount > 0 {
                textColor = .systemGreen
            }
            cell.textLabel?.textColor = textColor

            cell.textLabel?.numberOfLines = 0
            cell.textLabel?.text = "\(dateFormatter.string(from: transaction.date))\n\(transaction.type.rawValue.capitalized): \(transaction.description)\nAmount: \(transaction.amount.description)"
            cell.backgroundColor = .clear
            return cell
        }
    }

    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        if tableView == accountsTableView {
            selectedAccount = accounts[indexPath.row]
            updateUIForSelectedAccount()
        }
    }

    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        if tableView == accountsTableView {
            return "Your Accounts"
        } else {
            return "Transactions for \(selectedAccount?.name ?? "Selected Account")"
        }
    }
}

