import UIKit

class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?
    let cryptoHandler = CryptoHandler()
    lazy var bankingService = BankingService(cryptoHandler: cryptoHandler)

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }

        window = UIWindow(windowScene: windowScene)
        let rootVC = AccountListViewController(bankingService: bankingService)
        let navController = UINavigationController(rootViewController: rootVC)
        window?.rootViewController = navController
        window?.makeKeyAndVisible()
    }

    func sceneDidEnterBackground(_ scene: UIScene) {
        // Here you might want to save any pending data, clear sensitive UI, or trigger obfuscation.
        // Our BankingService already saves on every transaction for simplicity.
        // In a real app, this might be a good place for last-minute data persistence or cleanup.
    }

    func sceneWillResignActive(_ scene: UIScene) {
        // Consider blurring sensitive content, prompting for biometric re-authentication, etc.,
        // when the app is about to enter the background or become inactive.
    }
}

